findings.codeql_raw_query:
/**
 * @name Taint flow from user input to HTML output via HTMLScriptService
 * @description Track user-controlled content flowing to HTML output without encoding
 * @kind path-problem
 * @problem.severity error
 * @id java/xwiki-taint-html-output
 * @tags security
 *       external/cwe/cwe-079
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module XSSConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      (
        mc.getMethod().hasName("isElementAllowed") or
        mc.getMethod().hasName("isAttributeAllowed")
      ) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.xwiki.xml.html", "HTMLElementSanitizer") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module XSSFlow = TaintTracking::Global<XSSConfig>;
import XSSFlow::PathGraph

from XSSFlow::PathNode source, XSSFlow::PathNode sink
where XSSFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "User-controlled input reaches HTMLElementSanitizer check from $@.", source.getNode(), "source"
